import{_ as o,c as t,o as s,aq as r}from"./chunks/framework.jeRwkH3J.js";const p=JSON.parse('{"title":"Sources","description":"Frequently Asked Questions about Sources.","frontmatter":{"title":"Sources","description":"Frequently Asked Questions about Sources.","footer":false},"headers":[],"relativePath":"manuals/faq/explore/sources/index.md","filePath":"manuals/faq/explore/sources/index.md","lastUpdated":1776351368000,"breadcrumbs":[{"text":"User manual","link":"/manuals/guides/getting-started/"},{"text":"Frequently Asked Questions","items":[{"text":"General","link":"/manuals/faq/general/"},{"text":"Feed","link":"/manuals/faq/feed/"},{"text":"Explore","collapsed":true,"items":[{"text":"Sources","link":"/manuals/faq/explore/sources/"},{"text":"Downloads","link":"/manuals/faq/explore/downloads/"}]},{"text":"Reader","link":"/manuals/faq/reader/"},{"text":"Settings","link":"/manuals/faq/settings/"},{"text":"Miscellaneous","link":"/manuals/faq/miscellaneous/"}]},{"text":"Explore","collapsed":true,"items":[{"text":"Sources","link":"/manuals/faq/explore/sources/"},{"text":"Downloads","link":"/manuals/faq/explore/downloads/"}]},{"text":"Sources","link":"/manuals/faq/explore/sources/"}]}'),a={name:"manuals/faq/explore/sources/index.md"};function n(l,e,i,c,u,d){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="sources" tabindex="-1">Sources <a class="header-anchor" href="#sources" aria-label="Permalink to &quot;Sources&quot;">​</a></h1><p>Frequently Asked Questions about Sources.</p><h2 id="where-do-sources-content" tabindex="-1">Where do sources / content come from? <a class="header-anchor" href="#where-do-sources-content" aria-label="Permalink to &quot;Where do sources / content come from?&quot;">​</a></h2><p>Usagi can load content from offline sources (pre-downloaded content from local storage) or external plugins (<code>.jar</code>).</p><p>Install plugins from:</p><ul><li><strong>Settings</strong> -&gt; <strong>Sources</strong> -&gt; <strong>Manage plugins</strong> -&gt; <strong>Import from GitHub</strong></li><li><strong>Settings</strong> -&gt; <strong>Sources</strong> -&gt; <strong>Manage plugins</strong> -&gt; <strong>Import from local storage</strong></li></ul><h2 id="what-are-some-recommended" tabindex="-1">What are some recommended sources? <a class="header-anchor" href="#what-are-some-recommended" aria-label="Permalink to &quot;What are some recommended sources?&quot;">​</a></h2><p><strong>Usagi</strong> doesn&#39;t endorse or recommend any source, and no sources are currently available.</p><div class="info custom-block"><p class="custom-block-title">Disclaimer</p><p><strong>Usagi</strong> isn&#39;t responsible for the available content as it doesn&#39;t host content.</p></div><h2 id="how-do-i-request-new-sources" tabindex="-1">How do I request new sources? <a class="header-anchor" href="#how-do-i-request-new-sources" aria-label="Permalink to &quot;How do I request new sources?&quot;">​</a></h2><p><strong>Usagi</strong> doesn&#39;t make / create any source, and no sources are currently available. You can&#39;t request for any source unless you make / create it yourself.</p><div class="info custom-block"><p class="custom-block-title">Disclaimer</p><p><strong>Usagi</strong> isn&#39;t responsible for the available content as it doesn&#39;t host content.</p></div><h2 id="why-were-sources-removed" tabindex="-1">Why were sources removed? <a class="header-anchor" href="#why-were-sources-removed" aria-label="Permalink to &quot;Why were sources removed?&quot;">​</a></h2><p>Sources were removed for several reasons:</p><blockquote><ol><li>DMCA violation: This is a strong VIOLATION of copyrighted content.</li><li>Disadvantage: Users always feel uncomfortable when frequently encountering reading source problems. They are forced to wait until the next app update is released so the problem can be fixed.</li><li>Development: Programmers / Contributors have always found it difficult to run Test tasks on previous applications, they did not have many options. Most of them follow previous testing methods such as running directly on the integrated library (cannot test all cases) OR they are forced to build test applications (like Kotatsu Dev) to be able to test content after implement.</li><li>Forced removal of reported content: According to #39 on the old integrated library, some content was forced to be taken down at the owner&#39;s request, making it impossible for users to continue accessing that content.</li><li>Privacy: In some cases, some content has been hidden / encrypted by the owner, and you are allowed to exploit it by the owner. But the old built-in library is an open source library based on the GPL-3.0 license, which requires the library&#39;s source code to be completely public. From there, passwords, hidden tokens, decryption methods, etc. will be forced to be made public on the source code, allowing others to exploit them.</li></ol></blockquote>',15)])])}const h=o(a,[["render",n]]);export{p as __pageData,h as default};
